// components/ChatbotInterface.jsx - FIXED API CALLS
import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import './ERPChatBot.css';

// ✅ Create axios instance with base URL
const api = axios.create({
  baseURL: 'http://localhost:65000', // Same as StudentDashboard
  withCredentials: true, // CRITICAL for session cookies
  timeout: 10000 // 10 second timeout
});

const ChatbotInterface = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sessionId, setSessionId] = useState(null);
  const [userInfo, setUserInfo] = useState(null);
  const [isCheckingAuth, setIsCheckingAuth] = useState(true);

  // Initialize
  useEffect(() => {
    loadUserInfo();
    loadSavedMessages();
    
    // Load session ID
    const savedSessionId = localStorage.getItem('chatbotSessionId');
    if (savedSessionId) {
      setSessionId(savedSessionId);
    }
  }, []);

  // ✅ FIXED: Load user info properly
  const loadUserInfo = async () => {
    try {
      setIsCheckingAuth(true);
      
      // Try to get user info from API first
      const response = await api.get('/api/auth/me');
      
      console.log('Auth response:', response.data);
      
      if (response.data && response.data.user) {
        const userData = response.data.user;
        const userInfoObj = {
          id: userData._id,
          role: userData.role,
          studentId: userData.studentId || userData.username || 'unknown',
          email: userData.email || userData.universityEmail,
          name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
          firstName: userData.firstName
        };
        
        setUserInfo(userInfoObj);
        localStorage.setItem('userInfo', JSON.stringify(userInfoObj));
        
        // Also check chatbot status
        try {
          const statusRes = await api.get('/api/chatbot/status');
          console.log('Chatbot status:', statusRes.data);
        } catch (statusErr) {
          console.log('Chatbot status check failed:', statusErr.message);
        }
      } else {
        // Fallback to localStorage
        const stored = localStorage.getItem('userInfo');
        if (stored) {
          const userData = JSON.parse(stored);
          setUserInfo({
            id: userData._id,
            role: userData.role,
            studentId: userData.studentId || userData.username,
            email: userData.email || userData.universityEmail,
            name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
            firstName: userData.firstName
          });
        }
      }
    } catch (error) {
      console.log('Auth check failed, using localStorage:', error.message);
      
      // Fallback to localStorage
      const stored = localStorage.getItem('userInfo');
      if (stored) {
        const userData = JSON.parse(stored);
        setUserInfo({
          id: userData._id,
          role: userData.role,
          studentId: userData.studentId || userData.username,
          email: userData.email || userData.universityEmail,
          name: userData.fullName || `${userData.firstName || ''} ${userData.lastName || ''}`.trim(),
          firstName: userData.firstName
        });
      }
    } finally {
      setIsCheckingAuth(false);
    }
  };

  // ✅ FIXED: Send message with proper API call
  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    if (!inputMessage.trim() || isLoading) return;

    const userMessage = inputMessage.trim();
    setInputMessage('');
    
    // Add user message to chat
    const newUserMessage = {
      id: Date.now(),
      text: userMessage,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages(prev => [...prev, newUserMessage]);
    setIsLoading(true);

    try {
      console.log('Sending chat request...');
      
      // ✅ FIXED: Use the same axios instance with baseURL
      const response = await api.post('/api/chatbot/chat', {
        message: userMessage,
        sessionId: sessionId
      });

      console.log('Chat response:', response.data);

      if (response.data.success) {
        if (response.data.sessionId) {
          setSessionId(response.data.sessionId);
          localStorage.setItem('chatbotSessionId', response.data.sessionId);
        }

        const botMessage = {
          id: Date.now() + 1,
          text: response.data.response,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          metadata: response.data.metadata
        };
        
        setMessages(prev => [...prev, botMessage]);
      } else {
        addErrorMessage(response.data.message || "Something went wrong");
      }
    } catch (error) {
      console.error('Chat error details:', {
        message: error.message,
        response: error.response?.data,
        status: error.response?.status
      });
      
      // Handle specific error cases
      let errorText = "Sorry, I'm having trouble connecting. Please try again.";
      
      if (error.response) {
        switch (error.response.status) {
          case 401:
            errorText = "Please log in to use the chatbot.";
            // Clear user info on auth error
            setUserInfo(null);
            localStorage.removeItem('userInfo');
            break;
          case 403:
            errorText = "Chatbot is only available for students.";
            break;
          case 429:
            errorText = "Too many requests. Please wait a moment.";
            break;
          case 500:
            errorText = "Server error. Please try again later.";
            break;
          default:
            errorText = error.response.data?.message || "Something went wrong.";
        }
      } else if (error.request) {
        errorText = "Cannot connect to server. Check your internet connection.";
      }
      
      addErrorMessage(errorText);
    } finally {
      setIsLoading(false);
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  // ✅ FIXED: Load saved messages properly
  const loadSavedMessages = () => {
    try {
      const saved = localStorage.getItem('chatbot_messages');
      if (saved) {
        const parsed = JSON.parse(saved);
        // Keep only last 20 messages
        const recentMessages = parsed.slice(-20);
        setMessages(recentMessages);
      }
    } catch (e) {
      console.error('Error loading saved messages:', e);
      localStorage.removeItem('chatbot_messages');
    }
  };

  // Add other helper functions...

  // ✅ FIXED: Quick actions with base URL
  const handleQuickAction = async (text) => {
    if (!userInfo || userInfo.role !== 'student') {
      addSystemMessage("Please log in as a student to use quick actions.");
      return;
    }
    
    setInputMessage(text);
    // Auto-send after a delay
    setTimeout(() => {
      if (inputMessage === text) {
        handleSendMessage({ preventDefault: () => {} });
      }
    }, 300);
  };

  // Rest of the component remains similar...
};
